/**
 * @summary List responses for a form
 */
export const getListResponsesUrl = (
  id: string,
  params?: ListResponsesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/forms/${id}/responses?${stringifiedParams}`
    : `/api/forms/${id}/responses`;
};

export const listResponses = async (
  id: string,
  params?: ListResponsesParams,
  options?: RequestInit,
): Promise<PaginatedResponses> => {
  return customFetch<PaginatedResponses>(getListResponsesUrl(id, params), {
    ...options,
    method: "GET",
  });
};

export const getListResponsesQueryKey = (
  id: string,
  params?: ListResponsesParams,
) => {
  return [`/api/forms/${id}/responses`, ...(params ? [params] : [])] as const;
};

export const getListResponsesQueryOptions = <
  TData = Awaited<ReturnType<typeof listResponses>>,
  TError = ErrorType<unknown>,
>(
  id: string,
  params?: ListResponsesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listResponses>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListResponsesQueryKey(id, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listResponses>>> = ({
    signal,
  }) => listResponses(id, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listResponses>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListResponsesQueryResult = NonNullable<
  Awaited<ReturnType<typeof listResponses>>
>;
export type ListResponsesQueryError = ErrorType<unknown>;

